    json(conn, %{users: result.rows})
  end

  def by_email(conn, %{"email" => email}) do
    {:ok, result} = UserQuery.get_users_by_email(email)
    
    json(conn, %{users: result.rows})
  end

  def date_range(conn, %{"start_date" => start_date, "end_date" => end_date}) do
    {:ok, result} = UserQuery.get_users_by_date_range(start_date, end_date)
    
