defmodule MyAppWeb.Router do
  use MyAppWeb, :router

  pipeline :api do
    plug :accepts, ["json"]
  end

  scope "/admin", MyAppWeb.Admin do
    pipe_through :api

    get "/users", UserController, :index
    get "/users/search", UserController, :search
    get "/users/filter", UserController, :filter
    get "/users/by_status", UserController, :by_status
    get "/users/by_email", UserController, :by_email
    get "/users/date_range", UserController, :date_range
    get "/users/:user_id/orders", UserController, :orders
    delete "/users/delete", UserController, :delete
    put "/users/update_role", UserController, :update_role
    post "/users/custom", UserController, :custom
  end
end

